document.querySelectorAll(".copy-btn").forEach(e=>{e.addEventListener("click",()=>{const n=e.parentElement,s=n.querySelector("pre code")||n.querySelector("code");if(!s)return;const t=s.innerText;navigator.clipboard&&window.isSecureContext?navigator.clipboard.writeText(t).then(()=>showSuccess(e)).catch(n=>fallbackCopy(t,e)):fallbackCopy(t,e)})});function fallbackCopy(e,t){const n=document.createElement("textarea");n.value=e,n.style.position="fixed",n.style.left="-9999px",n.style.top="0",document.body.appendChild(n),n.focus(),n.select();try{const e=document.execCommand("copy");e&&showSuccess(t)}catch(e){console.error("Fallback copy failed",e)}document.body.removeChild(n)}function showSuccess(e){const t=e.innerText;e.innerText="Copied!",setTimeout(()=>{e.innerText=t},2e3)}